import { cacheTag } from 'next/cache';

/**
 * The catalog read is cached and tagged so every catalog view can share the
 * same data and an ERP sync can invalidate it in one operation.
 */
export async function getAllProducts() {
  'use cache';
  cacheTag('products');

  // Simulate a database delay.
  await new Promise((resolve) => setTimeout(resolve, 100));

  return [
    { id: 1, name: 'Laptop', price: 999, sku: 'TECH-LAP-001', inventory: 24, status: 'In stock', category: 'Computers' },
    { id: 2, name: 'Phone', price: 699, sku: 'TECH-PHN-002', inventory: 8, status: 'Low stock', category: 'Mobile' },
    { id: 3, name: 'Tablet', price: 499, sku: 'TECH-TAB-003', inventory: 0, status: 'Out of stock', category: 'Mobile' },
    { id: 4, name: 'Headphones', price: 199, sku: 'TECH-AUD-004', inventory: 46, status: 'In stock', category: 'Audio' },
    { id: 5, name: 'Watch', price: 299, sku: 'TECH-WAT-005', inventory: 12, status: 'In stock', category: 'Wearables' }
  ];
}
