import { revalidateTag } from 'next/cache';
import { getAllProducts } from '@/lib/db';
import './globals.css';

export default async function Page() {
  // This is intentionally a cached read. All catalog consumers use the same
  // tag, so a sync can refresh them together without making this request slow.
  const products = await getAllProducts();

  async function syncLatestCatalog() {
    'use server';

    // `max` gives the catalog stale-while-revalidate behavior: the action is
    // fast, existing data remains available, and the next read refreshes it
    // in the background rather than blocking an operator on thousands of SKUs.
    revalidateTag('products', 'max');
  }

  const inStock = products.filter((product) => product.inventory > 0).length;
  const lowStock = products.filter((product) => product.status === 'Low stock').length;

  return (
    <main className="shell">
      <aside className="sidebar">
        <div className="brand"><span className="brand-mark">N</span><span>northstar</span></div>
        <div className="workspace-label">Workspace</div>
        <div className="workspace"><span className="workspace-dot" />Acme Commerce <span className="chevron">⌄</span></div>
        <nav className="nav" aria-label="Main navigation">
          <a href="#"><span>⌂</span>Overview</a>
          <a className="active" href="#"><span>▦</span>Catalog <b>5</b></a>
          <a href="#"><span>◈</span>Orders</a>
          <a href="#"><span>◷</span>Customers</a>
        </nav>
        <div className="workspace-label bottom-label">Manage</div>
        <nav className="nav"><a href="#"><span>⚙</span>Settings</a><a href="#"><span>?</span>Help center</a></nav>
        <div className="profile"><div className="avatar">AM</div><div><strong>Alex Morgan</strong><small>Administrator</small></div><span className="dots">•••</span></div>
      </aside>

      <section className="content">
        <header className="topbar"><div className="breadcrumbs">Workspace <span>/</span> Catalog</div><div className="top-actions"><button className="icon-button" aria-label="Notifications">♧<i /></button><div className="top-avatar">AM</div></div></header>
        <div className="page-heading"><div><p className="eyebrow">INVENTORY MANAGEMENT</p><h1>Product catalog</h1><p className="subtitle">Manage your products, pricing, and availability.</p></div><form action={syncLatestCatalog}><button className="sync-button" type="submit"><span>↻</span> Sync latest catalog</button></form></div>

        <div className="stats"><div><span>Total products</span><strong>{products.length}</strong><small className="neutral">Across all categories</small></div><div><span>In stock</span><strong>{inStock}</strong><small className="positive">↑ 12% <em>vs last month</em></small></div><div><span>Low stock</span><strong>{lowStock}</strong><small className="warning">Needs attention</small></div><div><span>Last synced</span><strong className="sync-time">Just now</strong><small className="neutral">Automatically updated</small></div></div>

        <div className="table-card"><div className="table-toolbar"><div className="search"><span>⌕</span><input placeholder="Search products..." aria-label="Search products" /></div><div className="filters"><button>All categories <span>⌄</span></button><button>Filter <span>≡</span></button><button className="view-button" aria-label="List view">☷</button><button className="view-button muted" aria-label="Grid view">▦</button></div></div>
          <table><thead><tr><th className="check"><input type="checkbox" aria-label="Select all products" /></th><th>PRODUCT <span>↕</span></th><th>SKU <span>↕</span></th><th>PRICE <span>↕</span></th><th>INVENTORY <span>↕</span></th><th>STATUS</th><th /></tr></thead><tbody>{products.map((product) => <tr key={product.id}><td className="check"><input type="checkbox" aria-label={`Select ${product.name}`} /></td><td><div className="product"><div className={`product-image image-${product.id}`}><span>{product.id === 1 ? '▱' : product.id === 2 ? '▯' : product.id === 3 ? '▭' : product.id === 4 ? '◖' : '◉'}</span></div><div><strong>{product.name}</strong><small>{product.category}</small></div></div></td><td className="mono">{product.sku}</td><td className="price">${product.price.toLocaleString()}.00</td><td>{product.inventory} units</td><td><span className={`status ${product.status.toLowerCase().replaceAll(' ', '-')}`}><i />{product.status}</span></td><td><button className="row-menu" aria-label={`More actions for ${product.name}`}>•••</button></td></tr>)}</tbody></table>
          <footer className="table-footer"><span>Showing <b>1–{products.length}</b> of <b>{products.length}</b> products</span><div><button disabled>← Previous</button><button disabled>Next →</button></div></footer>
        </div>
        <p className="cache-note"><span>↻</span> Catalog data is cached for faster browsing. Syncing uses background refresh so you can keep working.</p>
      </section>
    </main>
  );
}
EOF
